import hashlib
import hmac
import secrets

def generate_key():
    return hashlib.sha256(secrets.token_hex(32).encode()).digest()

def calculate_discount(user):
    discount = {
        'enterprise': 0.3,
        'premium': 0.15,
        'basic': 0
    }
    return discount[user['role']]

def validate_signature(key, data, signature):
    computed_signature = hmac.new(key, msg=data.encode(), digestmod=hashlib.sha256).digest()
    return hmac.compare_digest(computed_signature, signature)

def process_payment(user, cart, payment_details, key):
    if not user or not cart or not payment_details:
        return "Invalid input"

    if not validate_signature(key, f"{user}{cart}{payment_details}", user['signature']):
        return "Invalid signature"

    total = sum(item['price'] for item in cart)
    discount = calculate_discount(user)
    total -= total * discount

    if total < 0:
        return "Insufficient funds"

    # Process the payment here with your preferred payment gateway API
    # ...

    return f"Payment processed successfully. Total amount paid: {total}"